from odoo import models, fields, api

class DepartmentProcess(models.Model):
    _name = 'hr.department.process'
    _description = 'Department Main Process'
    _order = 'sequence_number, id'
    _parent_name = 'parent_id'
    _parent_store = True

    name = fields.Char(string="Name", required=True)

    sequence_number = fields.Char(
        string="No",
        help="Hierarchical number (e.g., 1, 1.1, 1.2, 2). Auto-generated but editable."
    )

    parent_id = fields.Many2one(
        'hr.department.process',
        string="Parent Process",
        ondelete='cascade',
        index=True
    )

    parent_path = fields.Char(index=True, unaccent=False)

    child_ids = fields.One2many(
        'hr.department.process',
        'parent_id',
        string="Sub-processes"
    )

    document_ids = fields.Many2many(
        'document.library.item',
        'department_process_document_rel',
        'process_id',
        'document_id',
        string="Related Documents"
    )

    department_id = fields.Many2one(
        'hr.department',
        string="Department",
        required=True,
        ondelete='cascade'
    )

    sequence = fields.Integer(
        string="Sequence",
        default=10,
        help="Used for manual ordering within the same level"
    )

    @api.model_create_multi
    def create(self, vals_list):
        for vals in vals_list:
            if 'sequence_number' not in vals or not vals['sequence_number']:
                vals['sequence_number'] = self._generate_sequence_number(
                    vals.get('parent_id'),
                    vals.get('department_id')
                )
        return super().create(vals_list)

    def write(self, vals):
        # If parent changes and sequence_number is not explicitly set, regenerate
        if 'parent_id' in vals and 'sequence_number' not in vals:
            for record in self:
                vals['sequence_number'] = record._generate_sequence_number(
                    vals.get('parent_id'),
                    record.department_id.id
                )
        return super().write(vals)

    def _generate_sequence_number(self, parent_id, department_id):
        """Generate hierarchical sequence number based on parent and siblings"""
        if not parent_id:
            # Top level process - find next number
            existing = self.search([
                ('department_id', '=', department_id),
                ('parent_id', '=', False)
            ], order='sequence_number desc', limit=1)

            if existing and existing.sequence_number:
                try:
                    last_num = int(existing.sequence_number.split('.')[0])
                    return str(last_num + 1)
                except (ValueError, IndexError):
                    pass
            return "1"
        else:
            # Sub-process - append to parent number
            parent = self.browse(parent_id)
            if not parent.exists():
                return "1"

            existing = self.search([
                ('parent_id', '=', parent_id)
            ], order='sequence_number desc', limit=1)

            parent_num = parent.sequence_number or "1"

            if existing and existing.sequence_number:
                try:
                    # Extract the last part after the last dot
                    parts = existing.sequence_number.split('.')
                    last_part = int(parts[-1])
                    return f"{parent_num}.{last_part + 1}"
                except (ValueError, IndexError):
                    pass

            return f"{parent_num}.1"

    def name_get(self):
        """Display as 'No - Name' in dropdowns"""
        result = []
        for record in self:
            name = f"{record.sequence_number or ''} - {record.name}"
            result.append((record.id, name))
        return result


class Department(models.Model):
    _inherit = 'hr.department'

    process_ids = fields.One2many(
        'hr.department.process',
        'department_id',
        string="Main Processes"
    )

